package main
import("bufio";"crypto/sha256";"encoding/csv";"encoding/hex";"encoding/json";"flag";"io";"math";"os";"sort";"strconv")
type C struct{Category string `json:"category"`;Quantity int64 `json:"quantity"`;Value int64 `json:"valueMinorUnits"`};type A struct{ID string `json:"accountId"`;Value int64 `json:"valueMinorUnits"`}
type O struct{Benchmark string `json:"benchmark"`;Version int `json:"version"`;Count int64 `json:"recordCount"`;Quantity int64 `json:"totalQuantity"`;Value int64 `json:"totalValueMinorUnits"`;Categories []C `json:"categories"`;Accounts []A `json:"topAccounts"`;Min int64 `json:"minimumTransactionMinorUnits"`;Max int64 `json:"maximumTransactionMinorUnits"`;Checksum string `json:"checksum"`}
func main(){in:=flag.String("input","","");out:=flag.String("output","","");flag.Parse();f,_:=os.Open(*in);defer f.Close();r:=csv.NewReader(bufio.NewReader(f));r.Read();cm:=map[string]C{};am:=map[string]int64{};o:=O{"aggregation",1,0,0,0,nil,nil,math.MaxInt64,0,""};for{v,e:=r.Read();if e==io.EOF{break};q,_:=strconv.ParseInt(v[3],10,64);p,_:=strconv.ParseInt(v[4],10,64);x:=q*p;o.Count++;o.Quantity+=q;o.Value+=x;if x<o.Min{o.Min=x};if x>o.Max{o.Max=x};c:=cm[v[2]];c.Category=v[2];c.Quantity+=q;c.Value+=x;cm[v[2]]=c;am[v[1]]+=x};for _,c:=range cm{o.Categories=append(o.Categories,c)};sort.Slice(o.Categories,func(i,j int)bool{return o.Categories[i].Category<o.Categories[j].Category});for id,v:=range am{o.Accounts=append(o.Accounts,A{id,v})};sort.Slice(o.Accounts,func(i,j int)bool{if o.Accounts[i].Value==o.Accounts[j].Value{return o.Accounts[i].ID<o.Accounts[j].ID};return o.Accounts[i].Value>o.Accounts[j].Value});if len(o.Accounts)>10{o.Accounts=o.Accounts[:10]};h:=sha256.New();json.NewEncoder(h).Encode(struct{Categories []C;TopAccounts []A}{o.Categories,o.Accounts});o.Checksum=hex.EncodeToString(h.Sum(nil));b,_:=json.Marshal(o);os.WriteFile(*out,b,0644)}
